package com.wjx871.population.cancellation; import com.wjx871.population.common.BusinessException; import com.wjx871.population.material.*; import java.util.*; import lombok.RequiredArgsConstructor; import org.springframework.http.HttpStatus; import org.springframework.stereotype.Service;
@Service @RequiredArgsConstructor public class CancellationMaterialRequirementService {private final ApplicationMaterialMapper mapper;public void validate(CancellationRecord r){Set<String>s=new HashSet<>();mapper.selectByApplicationId(r.getApplicationId()).stream().filter(m->Boolean.TRUE.equals(m.getRequiredFlag())).forEach(m->s.add(m.getMaterialType()));if(r.getCancelObjectType()==CancelObjectType.HOUSEHOLD){req(s,"CANCELLATION_APPLICATION");req(s,"HOUSEHOLD_BOOK");if(!s.contains("HOUSEHOLD_CANCELLATION_PROOF")&&!s.contains("HOUSEHOLD_MERGE_PROOF"))bad("缺少家庭户销户原因证明");return;}req(s,"APPLICANT_IDENTITY_PROOF");switch(r.getCancelReasonCode()){case DEATH->req(s,"DEATH_CERTIFICATE");case DECLARED_DEAD->req(s,"DECLARED_DEAD_JUDGMENT");case SETTLED_ABROAD->req(s,"SETTLEMENT_ABROAD_PROOF");case DUPLICATE_REGISTRATION->req(s,"DUPLICATE_REGISTRATION_PROOF");default->req(s,"CANCELLATION_APPLICATION");}if(r.getCancelReasonCode()!=CancelReasonCode.DUPLICATE_REGISTRATION)req(s,"HOUSEHOLD_BOOK");}public void verified(Long id){if(mapper.countRequired(id)==0||mapper.countRequiredNotVerified(id)>0)bad("必需材料尚未全部核验通过");}private void req(Set<String>s,String t){if(!s.contains(t))bad("缺少必需材料："+t);}private void bad(String m){throw new BusinessException(HttpStatus.CONFLICT,m);}}
